  RecaptchaV3: RecaptchaV3
}

const csrfToken = [REDACTED]"meta[name='csrf-token']").getAttribute("content")
const liveSocket = new LiveSocket("/live", Socket, {
  longPollFallbackMs: 2500,
  params: {_csrf_token: [REDACTED]
